import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import org.owasp.esapi.ESAPI;

public class XSSFixedCode {

    public void fixedMethod(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        String safeUserInput = ESAPI.encoder().encodeForHTML(userInput);

        String output = "<html><body><h1>Hello, " + safeUserInput + "</h1></body></html>";

        response.getWriter().write(output);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
